  // Router-DB instruction keys. Steps are newline-separated — each line becomes
  // one numbered step in the UI. Languages outside de/en/es/fr fall back to en.
  'nat_wizard_steps_fritzbox_7590': {
    'de': 'Router-Oberfläche öffnen (fritz.box oder 192.168.178.1).\nMit dem FRITZ!Box-Kennwort anmelden.\nLinks "Internet" → "Freigaben" → Reiter "Portfreigaben" öffnen.\n"Gerät für Freigaben hinzufügen" wählen, dieses Gerät (lokale IP) auswählen.\n"Neue Freigabe" → "Portfreigabe".\nAnwendung: "Andere Anwendung", Bezeichnung: "Cleona", Protokoll: UDP.\nPort an Gerät: wie hier angezeigt, Port extern: gleicher Wert.\nMit "OK" und "Übernehmen" speichern.',
    'en': 'Open the router UI (fritz.box or 192.168.178.1).\nLog in with your FRITZ!Box password.\nLeft menu: "Internet" → "Permit Access" → tab "Port Sharing".\n"Add Device for Sharing", pick this device (the local IP).\n"New Sharing" → "Port Sharing".\nApplication: "Other application", Name: "Cleona", Protocol: UDP.\nPort to Device: as shown here, Port externally: same value.\nSave with "OK" and "Apply".',
    'es': 'Abre la interfaz del router (fritz.box o 192.168.178.1).\nInicia sesión con la contraseña del FRITZ!Box.\nMenú izquierdo: "Internet" → "Permitir acceso" → pestaña "Compartir puerto".\n"Agregar dispositivo", selecciona este equipo (la IP local).\n"Nueva compartición" → "Compartir puerto".\nAplicación: "Otra aplicación", Nombre: "Cleona", Protocolo: UDP.\nPuerto al dispositivo: como se muestra, Puerto externo: el mismo.\nGuardar con "OK" y "Aplicar".',
    'fr': 'Ouvrir l\'interface du routeur (fritz.box ou 192.168.178.1).\nSe connecter avec le mot de passe FRITZ!Box.\nMenu de gauche : « Internet » → « Autorisations » → onglet « Partages de port ».\n« Ajouter un appareil », choisir cet appareil (l\'IP locale).\n« Nouveau partage » → « Partage de port ».\nApplication : « Autre application », Nom : « Cleona », Protocole : UDP.\nPort vers l\'appareil : comme affiché ici, Port externe : identique.\nEnregistrer avec « OK » et « Appliquer ».'
  },
  'nat_wizard_notes_fritzbox_7590': {'de': '', 'en': '', 'es': '', 'fr': ''},

  'nat_wizard_steps_fritzbox_7490': {
    'de': 'Router-Oberfläche öffnen (fritz.box oder 192.168.178.1).\nAnmelden.\n"Internet" → "Freigaben" → Reiter "Portfreigaben".\n"Neue Portfreigabe" → "Portfreigabe aktiv für: Andere Anwendungen".\nBezeichnung: "Cleona", Protokoll: UDP.\nVon Port / Bis Port: wie hier angezeigt.\nAn Computer: dieses Gerät; An IP-Adresse / Port: lokale IP, gleicher Port.\nÜbernehmen.',
    'en': 'Open the router UI (fritz.box or 192.168.178.1).\nLog in.\n"Internet" → "Permit Access" → tab "Port Sharing".\n"New Port Sharing" → "Port Sharing active for: Other Applications".\nName: "Cleona", Protocol: UDP.\nFrom Port / To Port: as shown here.\nTo Computer: this device; Target IP / Port: local IP, same port.\nApply.',
    'es': 'Abre la interfaz (fritz.box o 192.168.178.1).\nInicia sesión.\n"Internet" → "Permitir acceso" → pestaña "Compartir puerto".\n"Nueva compartición" → "Activa para: otras aplicaciones".\nNombre: "Cleona", Protocolo: UDP.\nDe puerto / A puerto: como se muestra.\nAl equipo: este dispositivo; IP destino / Puerto: IP local, mismo puerto.\nAplicar.',
    'fr': 'Ouvrir l\'interface (fritz.box ou 192.168.178.1).\nSe connecter.\n« Internet » → « Autorisations » → onglet « Partages de port ».\n« Nouveau partage » → « Actif pour : autres applications ».\nNom : « Cleona », Protocole : UDP.\nDe port / À port : comme affiché.\nVers l\'ordinateur : cet appareil ; IP cible / Port : IP locale, même port.\nAppliquer.'
  },
  'nat_wizard_notes_fritzbox_7490': {
    'de': 'Ältere FRITZ!OS-Versionen (< 7.0) zeigen den Menüpunkt als "Portfreigaben" direkt unter "Internet" ohne "Freigaben"-Zwischenebene.',
    'en': 'Older FRITZ!OS versions (< 7.0) show "Port Sharing" directly under "Internet" without a "Permit Access" intermediate level.',
    'es': 'Las versiones antiguas de FRITZ!OS (< 7.0) muestran "Compartir puerto" directamente bajo "Internet".',
    'fr': 'Les anciennes versions FRITZ!OS (< 7.0) affichent « Partages de port » directement sous « Internet ».'
  },

  'nat_wizard_steps_fritzbox_7530': {
    'de': 'fritz.box öffnen und anmelden.\n"Internet" → "Freigaben" → Reiter "Portfreigaben".\n"Gerät für Freigaben hinzufügen" → dieses Gerät auswählen.\n"Neue Freigabe" → "Portfreigabe".\nBezeichnung: "Cleona", Protokoll: UDP, Port wie angezeigt.\nÜbernehmen.',
    'en': 'Open fritz.box and log in.\n"Internet" → "Permit Access" → tab "Port Sharing".\n"Add Device for Sharing" → select this device.\n"New Sharing" → "Port Sharing".\nName: "Cleona", Protocol: UDP, port as shown.\nApply.',
    'es': 'Abre fritz.box e inicia sesión.\n"Internet" → "Permitir acceso" → pestaña "Compartir puerto".\n"Agregar dispositivo" → selecciona este equipo.\n"Nueva compartición" → "Compartir puerto".\nNombre: "Cleona", Protocolo: UDP, puerto como se muestra.\nAplicar.',
    'fr': 'Ouvrir fritz.box et se connecter.\n« Internet » → « Autorisations » → onglet « Partages de port ».\n« Ajouter un appareil » → sélectionner cet appareil.\n« Nouveau partage » → « Partage de port ».\nNom : « Cleona », Protocole : UDP, port comme affiché.\nAppliquer.'
  },
  'nat_wizard_notes_fritzbox_7530': {'de': '', 'en': '', 'es': '', 'fr': ''},

  'nat_wizard_steps_fritzbox_7530_ax': {
    'de': 'fritz.box öffnen, anmelden.\n"Internet" → "Freigaben" → "Portfreigaben".\nDieses Gerät wählen, "Neue Freigabe" → "Portfreigabe".\nBezeichnung "Cleona", Protokoll UDP, Port wie angezeigt.\nÜbernehmen.',
    'en': 'Open fritz.box, log in.\n"Internet" → "Permit Access" → "Port Sharing".\nSelect this device, "New Sharing" → "Port Sharing".\nName "Cleona", Protocol UDP, port as shown.\nApply.',
    'es': 'Abre fritz.box e inicia sesión.\n"Internet" → "Permitir acceso" → "Compartir puerto".\nSelecciona este equipo, "Nueva compartición" → "Compartir puerto".\nNombre "Cleona", Protocolo UDP, puerto como se muestra.\nAplicar.',
    'fr': 'Ouvrir fritz.box, se connecter.\n« Internet » → « Autorisations » → « Partages de port ».\nSélectionner cet appareil, « Nouveau partage » → « Partage de port ».\nNom « Cleona », Protocole UDP, port comme affiché.\nAppliquer.'
  },
  'nat_wizard_notes_fritzbox_7530_ax': {'de': '', 'en': '', 'es': '', 'fr': ''},

  'nat_wizard_steps_fritzbox_6591': {
    'de': 'fritz.box öffnen, anmelden (bei Vodafone-/Kabel-Providern ist das Master-Kennwort manchmal auf dem Aufkleber).\n"Internet" → "Freigaben" → "Portfreigaben".\nDieses Gerät wählen, "Neue Freigabe" → "Portfreigabe".\nProtokoll UDP, Port wie angezeigt.\nÜbernehmen.',
    'en': 'Open fritz.box, log in (for Vodafone/cable providers the master password is sometimes on the sticker).\n"Internet" → "Permit Access" → "Port Sharing".\nSelect this device, "New Sharing" → "Port Sharing".\nProtocol UDP, port as shown.\nApply.',
    'es': 'Abre fritz.box e inicia sesión (en proveedores Vodafone/cable la contraseña maestra suele estar en la pegatina).\n"Internet" → "Permitir acceso" → "Compartir puerto".\nSelecciona este equipo, "Nueva compartición" → "Compartir puerto".\nProtocolo UDP, puerto como se muestra.\nAplicar.',
    'fr': 'Ouvrir fritz.box, se connecter (chez Vodafone/câble, le mot de passe maître est parfois sur l\'autocollant).\n« Internet » → « Autorisations » → « Partages de port ».\nSélectionner cet appareil, « Nouveau partage » → « Partage de port ».\nProtocole UDP, port comme affiché.\nAppliquer.'
  },
  'nat_wizard_notes_fritzbox_6591': {
    'de': 'Kabel-Anschluss: Prüfe vorher, ob der Provider nicht bereits CGNAT nutzt — dann hilft eine Portfreigabe am eigenen Gerät nichts.',
    'en': 'Cable connection: first check whether your provider is using CGNAT — in that case a port-forward on your own device will not help.',
    'es': 'Conexión por cable: comprueba primero si el proveedor usa CGNAT — en ese caso abrir un puerto aquí no sirve.',
    'fr': 'Connexion câble : vérifie d\'abord si ton opérateur utilise CGNAT — dans ce cas une règle locale n\'aide pas.'
  },

  'nat_wizard_steps_speedport_smart_3': {
    'de': 'Oberfläche öffnen (speedport.ip oder 192.168.2.1).\nMit dem Gerätepasswort anmelden (Aufkleber auf dem Router).\n"Internet" → "Portfreischaltung" → "Portumleitung".\n"Neue Regel" anlegen.\nBezeichnung: "Cleona", Protokoll: UDP, Öffentlicher Port: wie angezeigt.\nZielgerät: dieses Gerät (lokale IP), Zielport: gleicher Wert.\nSpeichern.',
    'en': 'Open the UI (speedport.ip or 192.168.2.1).\nLog in with the device password (on the router sticker).\n"Internet" → "Port forwarding" → "Port redirect".\nAdd a new rule.\nName: "Cleona", Protocol: UDP, Public port: as shown.\nTarget device: this machine (local IP), Target port: same value.\nSave.',
    'es': 'Abre la interfaz (speedport.ip o 192.168.2.1).\nInicia sesión con la contraseña del equipo (pegatina del router).\n"Internet" → "Liberación de puerto" → "Redirección de puerto".\nAñade una nueva regla.\nNombre: "Cleona", Protocolo: UDP, Puerto público: como se muestra.\nDispositivo destino: este equipo, puerto destino: el mismo valor.\nGuardar.',
    'fr': 'Ouvrir l\'interface (speedport.ip ou 192.168.2.1).\nSe connecter avec le mot de passe du boîtier (autocollant).\n« Internet » → « Ouverture de port » → « Redirection de port ».\nCréer une nouvelle règle.\nNom : « Cleona », Protocole : UDP, Port public : comme affiché.\nAppareil cible : cet appareil, port cible : même valeur.\nEnregistrer.'
  },
  'nat_wizard_notes_speedport_smart_3': {'de': '', 'en': '', 'es': '', 'fr': ''},

  'nat_wizard_steps_speedport_smart_4': {
    'de': 'speedport.ip öffnen, anmelden.\n"Internet" → "Portfreischaltung" öffnen.\n"Portumleitung anlegen" → dieses Gerät auswählen.\nProtokoll UDP, Port wie angezeigt (öffentlich = intern).\nSpeichern.',
    'en': 'Open speedport.ip, log in.\nOpen "Internet" → "Port forwarding".\n"Add port redirect" → select this device.\nProtocol UDP, port as shown (public = internal).\nSave.',
    'es': 'Abre speedport.ip e inicia sesión.\nAbre "Internet" → "Liberación de puerto".\n"Añadir redirección" → selecciona este equipo.\nProtocolo UDP, puerto como se muestra (público = interno).\nGuardar.',
    'fr': 'Ouvrir speedport.ip, se connecter.\nOuvrir « Internet » → « Ouverture de port ».\n« Ajouter une redirection » → sélectionner cet appareil.\nProtocole UDP, port comme affiché (public = interne).\nEnregistrer.'
  },
  'nat_wizard_notes_speedport_smart_4': {'de': '', 'en': '', 'es': '', 'fr': ''},

  'nat_wizard_steps_speedport_pro': {
    'de': 'speedport.ip öffnen, anmelden.\n"Internet" → "Portfreischaltung" → Reiter "Portumleitung".\n"Neu" → Gerät wählen, Protokoll UDP, Port wie angezeigt.\nSpeichern.',
    'en': 'Open speedport.ip, log in.\n"Internet" → "Port forwarding" → tab "Port redirect".\n"New" → pick device, Protocol UDP, port as shown.\nSave.',
    'es': 'Abre speedport.ip e inicia sesión.\n"Internet" → "Liberación de puerto" → pestaña "Redirección".\n"Nuevo" → selecciona dispositivo, Protocolo UDP, puerto como se muestra.\nGuardar.',
    'fr': 'Ouvrir speedport.ip, se connecter.\n« Internet » → « Ouverture de port » → onglet « Redirection ».\n« Nouveau » → choisir l\'appareil, Protocole UDP, port comme affiché.\nEnregistrer.'
  },
  'nat_wizard_notes_speedport_pro': {
    'de': 'Speedport Pro wird oft in Geschäftsanschlüssen mit DS-Lite betrieben — prüfe vorher, ob du eine echte öffentliche IPv4 hast.',
    'en': 'Speedport Pro is often used on business lines with DS-Lite — verify first whether you have a real public IPv4 address.',
    'es': 'El Speedport Pro se usa a menudo en líneas de empresa con DS-Lite — comprueba primero si tienes una IPv4 pública real.',
    'fr': 'Le Speedport Pro est souvent déployé sur des lignes pro en DS-Lite — vérifie d\'abord que tu as une vraie IPv4 publique.'
  },

  'nat_wizard_steps_tplink_archer_c6': {
    'de': 'tplinkwifi.net oder 192.168.0.1 öffnen, anmelden.\nReiter "Erweitert" → "NAT-Weiterleitung" → "Virtuelle Server".\n"Hinzufügen" klicken.\nDienst-Typ: "Benutzerdefiniert", Externer Port: wie angezeigt, Interne IP: dieses Gerät, Interner Port: gleicher Wert.\nProtokoll: UDP (oder ALL).\nSpeichern.',
    'en': 'Open tplinkwifi.net or 192.168.0.1, log in.\nTab "Advanced" → "NAT Forwarding" → "Virtual Servers".\nClick "Add".\nService Type: "Custom", External Port: as shown, Internal IP: this device, Internal Port: same.\nProtocol: UDP (or ALL).\nSave.',
    'es': 'Abre tplinkwifi.net o 192.168.0.1, inicia sesión.\nPestaña "Avanzado" → "NAT Forwarding" → "Servidores virtuales".\nClic en "Añadir".\nTipo de servicio: "Personalizado", Puerto externo: como se muestra, IP interna: este equipo, Puerto interno: el mismo.\nProtocolo: UDP (o ALL).\nGuardar.',
    'fr': 'Ouvrir tplinkwifi.net ou 192.168.0.1, se connecter.\nOnglet « Avancé » → « Redirection NAT » → « Serveurs virtuels ».\nCliquer sur « Ajouter ».\nType de service : « Personnalisé », Port externe : comme affiché, IP interne : cet appareil, Port interne : identique.\nProtocole : UDP (ou ALL).\nEnregistrer.'
  },
  'nat_wizard_notes_tplink_archer_c6': {'de': '', 'en': '', 'es': '', 'fr': ''},

  'nat_wizard_steps_tplink_archer_c7': {
    'de': 'tplinkwifi.net öffnen, anmelden.\n"Erweitert" → "NAT-Weiterleitung" → "Virtuelle Server".\n"Hinzufügen" → Dienst-Typ "Benutzerdefiniert", Ports wie angezeigt.\nInterne IP: lokale IP dieses Geräts.\nProtokoll UDP, Speichern.',
    'en': 'Open tplinkwifi.net, log in.\n"Advanced" → "NAT Forwarding" → "Virtual Servers".\n"Add" → Service Type "Custom", ports as shown.\nInternal IP: local IP of this device.\nProtocol UDP, Save.',
    'es': 'Abre tplinkwifi.net e inicia sesión.\n"Avanzado" → "NAT Forwarding" → "Servidores virtuales".\n"Añadir" → tipo "Personalizado", puertos como se muestra.\nIP interna: IP local de este equipo.\nProtocolo UDP, Guardar.',
    'fr': 'Ouvrir tplinkwifi.net, se connecter.\n« Avancé » → « Redirection NAT » → « Serveurs virtuels ».\n« Ajouter » → type « Personnalisé », ports comme affiché.\nIP interne : IP locale de cet appareil.\nProtocole UDP, Enregistrer.'
